// ── CHAPEL ICON ACT 2 — dynamic text ─────────────────────────
// Replaces static text; only mentions Sinhola if player has met them
function chapelIconAct2Text(G) {
  const hasSinhola = G.flags.has('met_sinhola');
  const hasButteranto = G.flags.has('met_butterantonio');
  const base = [
    "You lift it again. This time you know what you are looking at.",
  ];
  if (hasSinhola) {
    base.push("The script on the back \u2014 you have seen it now. In the container documentation that Sinhola translated. You can read fragments.");
  } else if (hasButteranto) {
    base.push("The script on the back \u2014 you have a better sense of it now. Butterantonio described the provenance document. Church Slavonic. Liturgical language.");
  } else {
    base.push("The script on the back. You have been in the container. You know the icons are from the same source.");
  }
  base.push(
    "It says: of the original pair. Entrusted. To be returned.",
    "The {ICON} in your cabin was placed here as part of the documentation of the transfer. You are the authentication. Your signature is what they need.",
    "You were sent here by whoever wants the transfer to succeed. Heritage Transfer Services sent you. The note at the bottom of your briefing said: Confirm only. Do not investigate further.",
    "You understand now what you were not supposed to investigate.",
    "You sit with this for a long time."
  );
  return base;
}



// ── DYNAMIC SCENE TEXT FUNCTIONS ──────────────────────────

// merky_cover_probe: tone shifts based on whether vespers_liberation fired
function merkyCoverProbeText(G) {
  const warm = G.flags.has('vespers_liberation') || G.flags.has('merky_alliance');
  const bg = G.cover.background ? G.cover.background.replace('bg_','').replace('_',' ') : 'your background';
  if (warm) {
    return [
      "Merky is in the mess when you return. They look up — not with suspicion. Something else.",
      `'I've been thinking,' they say. 'About what you said earlier. Before the collar, you said you were — ' They name what you told them. '${bg.charAt(0).toUpperCase()+bg.slice(1)}.'`,
      "A pause. Different from their usual pauses. More considering, less testing.",
      "'We had someone come through with the same background two crossings ago. Different circumstances.' They look at you. 'I'm not accusing you of anything. I'm just — noting it.'",
      "'The service last night was good,' they add, almost as an afterthought. 'Some of the crew thought so.'"
    ];
  }
  return [
    "Merky is in the mess when you return. They look up without quite seeming to.",
    `'I've been thinking,' they say. 'About what you said earlier. Before the collar, you said you were — ' They name what you told them. '${bg.charAt(0).toUpperCase()+bg.slice(1)}.'`,
    "A pause. Long enough to be intentional.",
    "'We had a chaplain two crossings ago who said the same thing. Different name. Different face. Same background.' They look at you. 'Is that common, in your training?'"
  ];
}



// ── DYNAMIC SCENE TEXT FUNCTIONS ──────────────────────────

function merkyCoverProbeText(G) {
  const warm = G.flags.has('vespers_liberation') || G.flags.has('merky_alliance');
  const bgRaw = G.cover.background || 'your background';
  const bg = bgRaw.replace('bg_','').replace(/_/g,' ');
  const bgLabel = bg.charAt(0).toUpperCase()+bg.slice(1);
  if (warm) {
    return [
      "Merky is in the mess when you return. They look up — not with suspicion. Something else.",
      `'I've been thinking,' they say. 'About what you said earlier. Before the collar, you said you were — ' They name what you told them. '${bgLabel}.'`,
      "A pause. Different from their usual pauses. More considering, less testing.",
      "'We had someone come through with the same background two crossings ago. Different circumstances.' They look at you. 'I'm not accusing you of anything. I'm just — noting it.'",
      "'The service last night was good,' they add, almost as an afterthought. 'Some of the crew thought so.'"
    ];
  }
  return [
    "Merky is in the mess when you return. They look up without quite seeming to.",
    `'I've been thinking,' they say. 'About what you said earlier. Before the collar, you said you were — ' They name what you told them. '${bgLabel}.'`,
    "A pause. Long enough to be intentional.",
    `'We had a chaplain two crossings ago who said the same thing. Different name. Different face. Same background.' They look at you. 'Is that common, in your training?'`
  ];
}

